import { useState, useEffect, useCallback, useRef } from "react";
import { GasReading, DataSource } from "../types";
import { fetchGasFromApis, generateSimulatedGas } from "../lib/gasApis";

const POLL_INTERVAL = 30_000; // 30 seconds
const ETH_PRICE_INTERVAL = 120_000; // 2 minutes

export function useGasData() {
  const [history, setHistory] = useState<GasReading[]>([]);
  const [ethPrice, setEthPrice] = useState<number | null>(null);
  const [ethPriceLoading, setEthPriceLoading] = useState(true);
  const [lastUpdate, setLastUpdate] = useState<Date>(new Date());
  const [countdown, setCountdown] = useState(30);
  const [dataSource, setDataSource] = useState<DataSource>("loading");
  const [sourceName, setSourceName] = useState<string>("");
  const [error, setError] = useState<string | null>(null);
  const [retryCount, setRetryCount] = useState(0);
  const isFetching = useRef(false);

  const fetchEthPrice = useCallback(async () => {
    try {
      const url = encodeURIComponent(
        "https://api.coingecko.com/api/v3/simple/price?ids=ethereum&vs_currencies=usd"
      );
      const res = await fetch(`/api/proxy?url=${url}`);
      const data = await res.json();
      if (data?.ethereum?.usd) {
        setEthPrice(data.ethereum.usd);
      }
    } catch {
      // Keep previous price on error
    } finally {
      setEthPriceLoading(false);
    }
  }, []);

  const fetchGas = useCallback(async () => {
    if (isFetching.current) return;
    isFetching.current = true;

    try {
      const result = await fetchGasFromApis();

      if (result) {
        // Live data success
        const reading: GasReading = {
          timestamp: Date.now(),
          slow: result.slow,
          standard: result.standard,
          fast: result.fast,
          instant: result.instant,
        };

        setHistory((h) => [...h, reading].slice(-20));
        setLastUpdate(new Date());
        setDataSource("live");
        setSourceName(result.source);
        setError(null);
        setRetryCount(0);

        // Use ethPrice from gas API if available and we don't have one yet
        if (result.ethPrice && !ethPrice) {
          setEthPrice(result.ethPrice);
        }
      } else {
        // All APIs failed — use simulation
        const sim = generateSimulatedGas();
        const reading: GasReading = {
          timestamp: Date.now(),
          slow: sim.slow,
          standard: sim.standard,
          fast: sim.fast,
          instant: sim.instant,
        };

        setHistory((h) => [...h, reading].slice(-20));
        setLastUpdate(new Date());
        setDataSource("simulated");
        setSourceName("simulated");
        setError("All live APIs unavailable. Using simulated data.");
        setRetryCount((c) => c + 1);
      }
    } catch (err) {
      // Unexpected error — use simulation
      const sim = generateSimulatedGas();
      const reading: GasReading = {
        timestamp: Date.now(),
        slow: sim.slow,
        standard: sim.standard,
        fast: sim.fast,
        instant: sim.instant,
      };

      setHistory((h) => [...h, reading].slice(-20));
      setLastUpdate(new Date());
      setDataSource("simulated");
      setSourceName("simulated");
      setError("Fetch error. Using simulated data.");
      setRetryCount((c) => c + 1);
    } finally {
      isFetching.current = false;
      setCountdown(30);
    }
  }, [ethPrice]);

  // Initial fetch + polling
  useEffect(() => {
    fetchGas();
    const id = setInterval(fetchGas, POLL_INTERVAL);
    return () => clearInterval(id);
  }, [fetchGas]);

  // Countdown timer
  useEffect(() => {
    const id = setInterval(() => {
      setCountdown((c) => Math.max(0, c - 1));
    }, 1000);
    return () => clearInterval(id);
  }, []);

  // ETH price fetch (CoinGecko as fallback/primary for USD)
  useEffect(() => {
    fetchEthPrice();
    const id = setInterval(fetchEthPrice, ETH_PRICE_INTERVAL);
    return () => clearInterval(id);
  }, [fetchEthPrice]);

  const current = history[history.length - 1] ?? null;

  return {
    current,
    history,
    ethPrice,
    ethPriceLoading,
    lastUpdate,
    countdown,
    dataSource,
    sourceName,
    error,
    retryCount,
    refetch: fetchGas,
  };
}

