import React from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from "recharts";
import { format } from "date-fns";
import { GasReading } from "../types";

interface GasChartProps {
  history: GasReading[];
}

function formatGweiTick(v: number): string {
  if (v >= 1) return `${Math.round(v)}`;
  if (v >= 0.01) return v.toFixed(2);
  return v.toFixed(3);
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (!active || !payload) return null;
  return (
    <div className="bg-zinc-900 border border-zinc-700 p-2 text-xs space-y-1">
      <div className="text-zinc-400">
        {format(new Date(label), "HH:mm:ss")}
      </div>
      {payload.map((p: any) => (
        <div key={p.dataKey} className="flex items-center gap-2">
          <span
            className="w-2 h-2 inline-block"
            style={{ background: p.color }}
          />
          <span className="text-zinc-300 capitalize">{p.dataKey}:</span>
          <span className="text-zinc-100 font-semibold">
            {typeof p.value === "number"
              ? p.value < 1
                ? p.value.toFixed(3)
                : p.value.toFixed(1)
              : p.value}{" "}
            gwei
          </span>
        </div>
      ))}
    </div>
  );
};

export default function GasChart({ history }: GasChartProps) {
  const data = history.map((r) => ({
    time: r.timestamp,
    slow: r.slow,
    standard: r.standard,
    fast: r.fast,
    instant: r.instant,
  }));

  return (
    <div className="w-full border border-zinc-800 bg-zinc-900/50 p-3">
      <div className="text-xs text-zinc-400 mb-2 font-semibold uppercase tracking-wider">
        Gas Price History (Last {history.length} readings)
      </div>
      <ResponsiveContainer width="100%" height={180}>
        <LineChart
          data={data}
          margin={{ top: 4, right: 8, bottom: 4, left: -10 }}
        >
          <CartesianGrid strokeDasharray="3 3" stroke="#27272a" />
          <XAxis
            dataKey="time"
            tickFormatter={(t) => format(new Date(t), "HH:mm:ss")}
            tick={{ fill: "#71717a", fontSize: 10 }}
            stroke="#3f3f46"
            interval="preserveStartEnd"
          />
          <YAxis
            tick={{ fill: "#71717a", fontSize: 10 }}
            stroke="#3f3f46"
            domain={["auto", "auto"]}
            tickFormatter={formatGweiTick}
          />
          <Tooltip content={<CustomTooltip />} />
          <Legend
            iconType="square"
            iconSize={8}
            wrapperStyle={{ fontSize: 10, color: "#a1a1aa" }}
          />
          <Line
            type="monotone"
            dataKey="slow"
            stroke="#34d399"
            strokeWidth={1.5}
            dot={false}
            activeDot={{ r: 3 }}
          />
          <Line
            type="monotone"
            dataKey="standard"
            stroke="#fbbf24"
            strokeWidth={1.5}
            dot={false}
            activeDot={{ r: 3 }}
          />
          <Line
            type="monotone"
            dataKey="fast"
            stroke="#fb923c"
            strokeWidth={1.5}
            dot={false}
            activeDot={{ r: 3 }}
          />
          <Line
            type="monotone"
            dataKey="instant"
            stroke="#f87171"
            strokeWidth={1.5}
            dot={false}
            activeDot={{ r: 3 }}
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

